  return { protocol: m[1] + ':', hostname: m[2], port: m[3] || null, path: m[4] || '/' };
}
function requestRaw(method, url, headers, body, timeoutMs = 120000) {
  return new Promise((resolve, reject) => {
    const p = parseUrl(url);
    const lib = p.protocol === 'https:' ? https : http;
    const req = lib.request({ hostname: p.hostname, port: p.port, path: p.path, method, headers: headers || {} }, res => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const text = Buffer.concat(chunks).toString();
        if (res.statusCode >= 400) return reject(new Error('HTTP ' + res.statusCode + ': ' + text));
